import{_ as l,o as a,c as o,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"《文明、现代化、价值投资与中国》深度解读系列","description":"李录著作读书笔记：从文明演进到价值投资，用跨学科视角理解中国现代化的独特路径与投资智慧","frontmatter":{"title":"《文明、现代化、价值投资与中国》深度解读系列","description":"李录著作读书笔记：从文明演进到价值投资，用跨学科视角理解中国现代化的独特路径与投资智慧","pubDate":"2026-05-16","heroImage":"/images/lilu-book/00007.jpeg"},"headers":[],"relativePath":"posts/lilu-book-index.md","filePath":"posts/lilu-book-index.md"}'),i={name:"posts/lilu-book-index.md"};function e(n,t,s,h,d,g){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="《文明、现代化、价值投资与中国》深度解读系列" tabindex="-1">《文明、现代化、价值投资与中国》深度解读系列 <a class="header-anchor" href="#《文明、现代化、价值投资与中国》深度解读系列" aria-label="Permalink to &quot;《文明、现代化、价值投资与中国》深度解读系列&quot;">​</a></h1><h2 id="关于本书" tabindex="-1">关于本书 <a class="header-anchor" href="#关于本书" aria-label="Permalink to &quot;关于本书&quot;">​</a></h2><p>《文明、现代化、价值投资与中国》是喜马拉雅资本创始人李录的代表作，由中信出版集团于2020年出版。本书汇集了李录30多年来对现代化问题的思考，以及他在价值投资领域的深刻洞见。</p><p><strong>作者背景：</strong></p><ul><li>李录，喜马拉雅资本创始人、董事长</li><li>查理·芒格家族资产的主要管理者</li><li>被芒格称为&quot;中国的沃伦·巴菲特&quot;</li><li>北京大学光华管理学院价值投资课程主讲人</li></ul><p><strong>本书结构：</strong></p><ul><li><strong>上篇：文明、现代化与中国</strong> — 从人类文明演化史角度解读现代化的本质</li><li><strong>下篇：价值投资与理性思考</strong> — 价值投资的理念、实践与中国应用</li></ul><h2 id="核心洞见" tabindex="-1">核心洞见 <a class="header-anchor" href="#核心洞见" aria-label="Permalink to &quot;核心洞见&quot;">​</a></h2><h3 id="_1-人类文明的三阶段划分" tabindex="-1">1. 人类文明的三阶段划分 <a class="header-anchor" href="#_1-人类文明的三阶段划分" aria-label="Permalink to &quot;1. 人类文明的三阶段划分&quot;">​</a></h3><p>李录将人类文明划分为三个阶段：</p><ul><li><strong>1.0文明（狩猎时代）</strong>：始于15万年前，人类与其他动物差别不大</li><li><strong>2.0文明（农业文明）</strong>：始于公元前9000年，创造了强大的GDP能力，但存在发展天花板</li><li><strong>3.0文明（现代科技文明）</strong>：始于1750年左右，经济持续累进增长，是人类历史上前所未有的现象</li></ul><h3 id="_2-现代化的本质" tabindex="-1">2. 现代化的本质 <a class="header-anchor" href="#_2-现代化的本质" aria-label="Permalink to &quot;2. 现代化的本质&quot;">​</a></h3><blockquote><p><strong>现代化就是当现代科技与市场经济相结合时所产生的经济无限累进增长的现象。</strong></p></blockquote><p>这一洞见揭示了为什么过去200年人类经济出现了爆发式增长，而在此前的16000年里，经济增长几乎是平的。</p><h3 id="_3-3-0文明的铁律" tabindex="-1">3. 3.0文明的铁律 <a class="header-anchor" href="#_3-3-0文明的铁律" aria-label="Permalink to &quot;3. 3.0文明的铁律&quot;">​</a></h3><p>一个自由竞争的市场就是一个不断自我进化、自我进步、自我完善的机制。最大的市场最终会成为唯一的市场，任何人、企业、社会、国家，离开这个最大的市场之后就会不断落后。</p><h3 id="_4-价值投资的四大理念" tabindex="-1">4. 价值投资的四大理念 <a class="header-anchor" href="#_4-价值投资的四大理念" aria-label="Permalink to &quot;4. 价值投资的四大理念&quot;">​</a></h3><ol><li><strong>股票是对公司的部分所有权</strong> — 投资正道，分享公司价值增长</li><li><strong>市场是为投资者服务的</strong> — 利用市场，而非被市场左右</li><li><strong>安全边际</strong> — 预留足够空间应对预测的不确定性</li><li><strong>能力圈</strong> — 通过长期努力建立对特定公司的深度理解</li></ol><h2 id="阅读指南" tabindex="-1">阅读指南 <a class="header-anchor" href="#阅读指南" aria-label="Permalink to &quot;阅读指南&quot;">​</a></h2><h3 id="适合读者" tabindex="-1">适合读者 <a class="header-anchor" href="#适合读者" aria-label="Permalink to &quot;适合读者&quot;">​</a></h3><ul><li>对中国现代化进程感兴趣的读者</li><li>价值投资学习者和实践者</li><li>希望建立跨学科思维框架的思考者</li><li>关心中国经济未来的投资者</li></ul><h3 id="阅读顺序建议" tabindex="-1">阅读顺序建议 <a class="header-anchor" href="#阅读顺序建议" aria-label="Permalink to &quot;阅读顺序建议&quot;">​</a></h3><ol><li><strong>先看上篇前3章</strong> — 建立人类文明演化的宏观视角</li><li><strong>重点阅读&quot;现代化的诞生&quot;和&quot;现代化的本质&quot;</strong> — 理解现代化的核心机制</li><li><strong>下篇价值投资部分</strong> — 结合实践案例深入理解</li><li><strong>最后阅读中国预测章节</strong> — 形成对未来的判断框架</li></ol><h3 id="学习方法" tabindex="-1">学习方法 <a class="header-anchor" href="#学习方法" aria-label="Permalink to &quot;学习方法&quot;">​</a></h3><ul><li><strong>对比阅读</strong>：与《枪炮、病菌与钢铁》《西方将主宰多久》对照阅读</li><li><strong>图表分析</strong>：重点关注书中的人类文明发展曲线图</li><li><strong>案例思考</strong>：结合中国改革开放40年的实践验证理论</li><li><strong>投资实践</strong>：用价值投资理念分析具体公司</li></ul><h2 id="章节导航" tabindex="-1">章节导航 <a class="header-anchor" href="#章节导航" aria-label="Permalink to &quot;章节导航&quot;">​</a></h2><h3 id="上篇-文明、现代化与中国" tabindex="-1">上篇：文明、现代化与中国 <a class="header-anchor" href="#上篇-文明、现代化与中国" aria-label="Permalink to &quot;上篇：文明、现代化与中国&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>核心内容</th></tr></thead><tbody><tr><td>1</td><td><a href="/posts/lilu-book-ch1.html">老问题和新史学</a></td><td>新史学方法论与跨学科研究</td></tr><tr><td>2</td><td><a href="/posts/lilu-book-ch2.html">现代化的诞生——1776年的三大革命</a></td><td>亚当·斯密、《独立宣言》、蒸汽机</td></tr><tr><td>3</td><td><a href="/posts/lilu-book-ch3.html">现代化的本质和铁律</a></td><td>3.0文明的核心机制与全球化铁律</td></tr><tr><td>4</td><td><a href="/posts/lilu-book-ch4.html">价值投资在中国的展望</a></td><td>价值投资的四大核心理念</td></tr></tbody></table><p><em>更多章节持续更新中...</em></p><h2 id="核心概念速查" tabindex="-1">核心概念速查 <a class="header-anchor" href="#核心概念速查" aria-label="Permalink to &quot;核心概念速查&quot;">​</a></h2><h3 id="文明相关" tabindex="-1">文明相关 <a class="header-anchor" href="#文明相关" aria-label="Permalink to &quot;文明相关&quot;">​</a></h3><ul><li><strong>1.0/2.0/3.0文明</strong>：人类文明的三个发展阶段</li><li><strong>新史学</strong>：利用跨学科科学工具研究人类长期历史的方法论</li><li><strong>米兰科维奇循环</strong>：地球气候10万年大循环理论</li><li><strong>非洲夏娃/亚当</strong>：现代人类共同祖先理论</li></ul><h3 id="经济相关" tabindex="-1">经济相关 <a class="header-anchor" href="#经济相关" aria-label="Permalink to &quot;经济相关&quot;">​</a></h3><ul><li><strong>自由市场经济</strong>：1+1&gt;2的分工交换效应</li><li><strong>知识复利</strong>：1+1&gt;4的思想碰撞效应</li><li><strong>累进增长</strong>：经济持续复利增长的现象</li><li><strong>安全边际</strong>：价值投资的核心保护机制</li></ul><h3 id="投资相关" tabindex="-1">投资相关 <a class="header-anchor" href="#投资相关" aria-label="Permalink to &quot;投资相关&quot;">​</a></h3><ul><li><strong>受托人责任</strong>：资产管理行业的道德底线</li><li><strong>能力圈</strong>：投资者的能力边界</li><li><strong>市场先生</strong>：市场的非理性特征</li><li><strong>正道/邪道</strong>：可持续与不可持续的投资方式</li></ul><h2 id="实战工具" tabindex="-1">实战工具 <a class="header-anchor" href="#实战工具" aria-label="Permalink to &quot;实战工具&quot;">​</a></h2><h3 id="分析框架" tabindex="-1">分析框架 <a class="header-anchor" href="#分析框架" aria-label="Permalink to &quot;分析框架&quot;">​</a></h3><ol><li><strong>文明演化分析框架</strong>：从1.0到3.0文明的转型特征</li><li><strong>现代化程度评估</strong>：2.5文明的判断标准</li><li><strong>价值投资四原则检查清单</strong></li><li><strong>能力圈边界划定方法</strong></li></ol><h3 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h3><ul><li>《枪炮、病菌与钢铁》- 贾雷德·戴蒙德</li><li>《西方将主宰多久》- 伊恩·莫里斯</li><li>《国富论》- 亚当·斯密</li><li>《聪明的投资者》- 本杰明·格雷厄姆</li><li>《穷查理宝典》- 查理·芒格</li></ul><h2 id="系列文章说明" tabindex="-1">系列文章说明 <a class="header-anchor" href="#系列文章说明" aria-label="Permalink to &quot;系列文章说明&quot;">​</a></h2><p>本系列读书笔记采用<strong>黑天鹅分析方法</strong>，重点关注：</p><ol><li><strong>极端影响</strong>：书中哪些观点具有改变认知的冲击力</li><li><strong>不可预测性</strong>：历史转折点的偶然与必然</li><li><strong>事后解释</strong>：成功理论的叙事陷阱</li><li><strong>反脆弱性</strong>：如何在不确定性中获益</li></ol><p>每篇文章将包含：</p><ul><li>核心概念详解</li><li>实际案例分析</li><li>常见陷阱与误区</li><li>实战应用建议</li><li>批判性思考</li></ul><hr><p><em>本系列基于李录《文明、现代化、价值投资与中国》整理，仅供学习交流使用。</em></p>',48)])])}const b=l(i,[["render",e]]);export{c as __pageData,b as default};
